public class Solution {
    public int maxFrequency(int[] nums, int k) {
        Arrays.sort(nums);
        int n = nums.length, i = 0;
        long sum = 0;
        int max_freq = 0;

        for (int j = 0; j < n; j++) {
            sum += nums[j];
            while (sum + k < (long) nums[j] * (j - i + 1)) {
                sum -= nums[i++];
            }
            max_freq = Math.max(max_freq, j - i + 1);
        }

        return max_freq;
    }
}

