public class Solution {
    public int numOfWays(int m, int n) {
        long mod = 1000000007;
        long a = 6, b = 6, c = 3, d = 3;
        while (--n > 0) {
            long temp_a = a, temp_c = c;
            a = (a * 3 + b * 2) % mod;
            b = (temp_a * 2 + b * 2) % mod;
            c = (c * 3 + d * 2) % mod;
            d = (temp_c * 2 + d * 2) % mod;
        }
        return (int)(m == 1 ? b : (a + c) % mod);
    }
}

