public class Solution {
    public int maxQuality_dfs(int node, int time_left, int[] visited, int[] values, List<List<int[]>> neighbors) {
        int acc = 0;
        for (int[] edge : neighbors.get(node)) {
            int neighbor = edge[0], cost = edge[1];
            if (time_left >= cost && visited[neighbor] == 0) {
                visited[neighbor] = 1;
                acc = Math.max(acc, values[neighbor] + maxQuality_dfs(neighbor, time_left - cost, visited, values, neighbors));
                visited[neighbor] = 0;
            }
        }
        return acc;
    }

    public int maxQuality(int[] values, int[][] edges, int maxTime) {
        List<List<int[]>> neighbors = new ArrayList<>();
        for (int i = 0; i < values.length; i++) {
            neighbors.add(new ArrayList<>());
        }
        for (int[] edge : edges) {
            neighbors.get(edge[0]).add(new int[]{edge[1], edge[2]});
            neighbors.get(edge[1]).add(new int[]{edge[0], edge[2]});
        }
        int[] visited = new int[values.length];
        return maxQuality_dfs(0, maxTime, visited, values, neighbors);
    }
}

