    int minSumOfSquaredDifference(int[] nums1, int[] nums2, int k1, int k2) {
        long res = 0;
        for (int i = 0; i < nums1.length; ++i) {
            int diff = Math.abs(nums1[i] - nums2[i]);
            int steps = Math.min(k1 + k2, diff);
            diff -= steps;
            k1 -= Math.min(k1, steps);
            res += (long)diff * diff;
        }
        return (int)res;
    }
}

