public class Solution {
    final int MOD = 1000000007;
    final int MAX = 1001;

    int ways(int startPos, int endPos, int k, int[][] dp) {
        if (k == 0) return startPos == endPos ? 1 : 0;
        if (startPos < 0 || endPos < 0 || startPos >= MAX || endPos >= MAX) return 0;

        if (dp[startPos][k] != -1) return dp[startPos][k];

        int left = ways(startPos - 1, endPos, k - 1, dp);
        int right = ways(startPos + 1, endPos, k - 1, dp);

        return dp[startPos][k] = (left + right) % MOD;
    }

    int numberOfWays(int startPos, int endPos, int k) {
        int[][] dp = new int[MAX][k + 1];
        for (int[] row : dp) Arrays.fill(row, -1);
        return ways(startPos, endPos, k, dp);
    }
}

